sql:
SELECT movie_name
FROM movies
WHERE movie_id = 1;

external_knowledge:
- 'recent flicks' refers to movies released in the year 2022;
- 'highly regarded' indicates movies with higher average ratings;
- 'average user ratings' refers to the average of the `rating_value` given by users for each movie.

sql:
SELECT COUNT(*) AS total_movies
FROM movies
WHERE year = 2013 AND rating >= 8;
